example.code:
-- Query: orders by user sorted by date
CREATE INDEX idx_orders_user_created ON orders(user_id, created_at DESC);

-- Partial index: only index pending orders (avoids indexing shipped/delivered)
CREATE INDEX idx_orders_status_pending ON orders(created_at)
    WHERE status = 'pending';

-- Trigram index for product name search
CREATE INDEX idx_products_name_trgm ON products
    USING gin(name gin_trgm_ops);

-- Partial index for active users only
CREATE INDEX idx_users_email_active ON users(email)
    WHERE deleted_at IS NULL;

-- BAD: composite index won't serve WHERE created_at > ? ORDER BY status
CREATE INDEX idx_status_created ON orders(status, created_at);
-- Use: (created_at, status) if filtering on created_at range with status in ORDER BY
